23	const PROCESSING_FEE = 5;
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	const BUILDING_BLOCK_PREMIUM = 60;
26	const BUILDING_BLOCK_SIZE = 3;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
