36	const countItemsByType = (items: Item[]): Record<string, number> => {
37	  const counts: Record<string, number> = {};
38	  for (const item of items) {
39	    counts[item.type] = (counts[item.type] || 0) + 1;
40	  }
41	  return counts;
42	};
43	
44	const calculateBasePremium = (items: Item[]): number => {
45	  const typeCounts = countItemsByType(items);
46	  let total = 0;
47	
48	  for (const [type, count] of Object.entries(typeCounts)) {
49	    if (count === BUILDING_BLOCK_SIZE) {
50	      total += BUILDING_BLOCK_PREMIUM;
51	    } else {
52	      total += BASE_PREMIUMS[type] * count;
53	    }
54	  }
55	
56	  return total;
57	};
58	
59	export function processScenario(scenario: Scenario): ScenarioOutput {
60	  const step = scenario.steps[0];
61	  const basePremium = calculateBasePremium(step.items);
62	  const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
63	  return { results: [{ premium }] };
64	}
